import Fixture from '../../data/interfaces/fixture';
import FixtureSummaryData from './fixture-summary-data';

const FixtureSummary = (props : {tigersResults : Fixture[], panthersResults : Fixture[]}) => {

    const {tigersResults, panthersResults} = props;

    return (
       <table className="table table-hover table-condensed table-responsive">
            <thead>
                <tr>
                    <th>Team</th>
                    <th>Played</th>
                    <th>W</th>
                    <th>D</th>
                    <th>L</th>
                    <th>GF</th>
                    <th>GA</th>                            
                    <th>GD</th>
                    <th>PTS</th>
                </tr>
            </thead>
            <tbody>
                <FixtureSummaryData team={"Tigers"} summaryResults={tigersResults}/>
                <FixtureSummaryData team={"Panthers"} summaryResults={panthersResults}/>
            </tbody>
        </table>        
    );

}
export default FixtureSummary;
